### 1. Decryption Fuzzer
```rust
// fuzz/fuzz_targets/decrypt.rs
#![no_main]

use libfuzzer_sys::fuzz_target;
use arbitrary::Arbitrary;
use coding_agent_search::export::crypto::{decrypt_with_password, KeySlot};

#[derive(Arbitrary, Debug)]
struct DecryptInput {
    ciphertext: Vec<u8>,
    password: String,
    salt: [u8; 16],
    nonce_prefix: [u8; 4],
    kdf_m_cost: u32,
    kdf_t_cost: u32,
    kdf_p_cost: u32,
}

fuzz_target!(|input: DecryptInput| {
    // Clamp KDF params to reasonable ranges to avoid OOM
    let m_cost = (input.kdf_m_cost % 65536).max(1024);
    let t_cost = (input.kdf_t_cost % 4).max(1);
    let p_cost = (input.kdf_p_cost % 4).max(1);

    let key_slot = KeySlot {
        kdf: "argon2id".to_string(),
        kdf_params: serde_json::json!({
            "m_cost": m_cost,
            "t_cost": t_cost,
            "p_cost": p_cost,
            "salt": base64::encode(&input.salt),
        }),
        encrypted_dek: vec![0u8; 48], // 32 byte key + 16 byte tag
        nonce_prefix: input.nonce_prefix.to_vec(),
    };

    // This should never panic, only return errors
    let _ = decrypt_with_password(
        &input.ciphertext,
        &input.password,
        &key_slot,
    );
});
```

### 2. KDF Fuzzer
```rust
// fuzz/fuzz_targets/kdf.rs
#![no_main]

use libfuzzer_sys::fuzz_target;
use arbitrary::Arbitrary;
use coding_agent_search::export::crypto::{derive_key_argon2id, derive_key_hkdf};

#[derive(Arbitrary, Debug)]
struct KdfInput {
    password: Vec<u8>,
    salt: Vec<u8>,
    use_hkdf: bool,
}

fuzz_target!(|input: KdfInput| {
    // Ensure salt is at least minimum size
    let salt = if input.salt.len() < 16 {
        let mut padded = input.salt.clone();
        padded.resize(16, 0);
        padded
    } else {
        input.salt[..16].to_vec()
    };

    if input.use_hkdf {
        // HKDF should handle any input without panicking
        let _ = derive_key_hkdf(&input.password, &salt);
    } else {
        // Argon2id with minimal params for fuzzing speed
        let _ = derive_key_argon2id(
            &input.password,
            &salt,
            1024,  // Minimal memory for fuzzing
            1,     // Single iteration
            1,     // Single thread
        );
    }
});
```

