//! Test data generation utilities for optimization testing

use rand::{Rng, SeedableRng};
use rand_chacha::ChaCha8Rng;
use std::path::PathBuf;

/// Deterministic RNG for reproducible tests
pub fn seeded_rng(seed: u64) -> ChaCha8Rng {
    ChaCha8Rng::seed_from_u64(seed)
}

/// Generate realistic conversation metadata
pub fn generate_metadata(rng: &mut impl Rng, id: usize) -> ConversationMetadata {
    let agents = ["claude", "codex", "cursor", "gemini", "aider"];
    let agent = agents[rng.gen_range(0..agents.len())];

    ConversationMetadata {
        source_path: format!("/home/user/.{}/projects/project_{}/sessions/{}.jsonl", 
            agent, id / 100, id),
        agent_type: agent.to_string(),
        timestamp: 1704067200 + (id as i64) * 3600, // Hourly sessions starting 2024-01-01
        line_number: Some(rng.gen_range(1..1000)),
        message_count: rng.gen_range(5..500),
        total_chars: rng.gen_range(1000..100000),
        ..Default::default()
    }
}

/// Generate realistic content for indexing
pub fn generate_content(rng: &mut impl Rng, length: usize) -> String {
    let words = [
        "function", "variable", "struct", "impl", "trait", "async", "await",
        "error", "result", "option", "vec", "string", "iterator", "closure",
        "lifetime", "borrow", "reference", "mutable", "const", "static",
        "pub", "mod", "use", "crate", "super", "self", "where", "type",
    ];

    let mut content = String::with_capacity(length);
    while content.len() < length {
        let word = words[rng.gen_range(0..words.len())];
        if !content.is_empty() {
            content.push(' ');
        }
        content.push_str(word);

        // Occasionally add numbers or punctuation
        if rng.gen_ratio(1, 5) {
            content.push_str(&format!("{}", rng.gen_range(0..1000)));
        }
        if rng.gen_ratio(1, 10) {
            content.push_str("()\n");
        }
    }
    content
}

/// Generate test documents for FTS5 indexing
pub fn generate_documents(count: usize, seed: u64) -> Vec<Document> {
    let mut rng = seeded_rng(seed);
    (0..count)
        .map(|i| Document {
            rowid: i as i64,
            source_path: format!("/test/path/{}.jsonl", i),
            content: generate_content(&mut rng, rng.gen_range(100..1000)),
        })
        .collect()
}

/// Generate test embeddings (f16 vectors)
pub fn generate_embeddings(count: usize, dim: usize, seed: u64) -> Vec<Vec<half::f16>> {
    let mut rng = seeded_rng(seed);
    (0..count)
        .map(|_| {
            (0..dim)
                .map(|_| half::f16::from_f32(rng.gen_range(-1.0..1.0)))
                .collect()
        })
        .collect()
}

/// Generate path mappings for workspace trie testing
pub fn generate_path_mappings(count: usize, seed: u64) -> Vec<(String, String)> {
    let mut rng = seeded_rng(seed);
    (0..count)
        .map(|i| {
            let depth = rng.gen_range(2..6);
            let from_parts: Vec<String> = (0..depth)
                .map(|_| format!("dir{}", rng.gen_range(0..100)))
                .collect();
            let to_parts: Vec<String> = (0..depth)
                .map(|_| format!("mapped{}", rng.gen_range(0..100)))
                .collect();
            (
                format!("/home/user/{}", from_parts.join("/")),
                format!("/Users/me/{}", to_parts.join("/")),
            )
        })
        .collect()
}
