//! Performance measurement utilities

use std::time::{Duration, Instant};

/// Measure execution time with warmup and multiple iterations
pub struct PerfMeasurement {
    pub warmup_runs: usize,
    pub measured_runs: usize,
    pub times: Vec<Duration>,
}

impl PerfMeasurement {
    pub fn new(warmup: usize, measured: usize) -> Self {
        Self {
            warmup_runs: warmup,
            measured_runs: measured,
            times: Vec::with_capacity(measured),
        }
    }

    /// Run a function multiple times and collect timing
    pub fn measure<F, R>(&mut self, mut f: F) -> R
    where
        F: FnMut() -> R,
    {
        // Warmup runs
        let mut result = None;
        for _ in 0..self.warmup_runs {
            result = Some(f());
        }

        // Measured runs
        for _ in 0..self.measured_runs {
            let start = Instant::now();
            result = Some(f());
            self.times.push(start.elapsed());
        }

        result.unwrap()
    }

    pub fn mean(&self) -> Duration {
        if self.times.is_empty() {
            return Duration::ZERO;
        }
        self.times.iter().sum::<Duration>() / self.times.len() as u32
    }

    pub fn median(&self) -> Duration {
        if self.times.is_empty() {
            return Duration::ZERO;
        }
        let mut sorted = self.times.clone();
        sorted.sort();
        sorted[sorted.len() / 2]
    }

    pub fn std_dev(&self) -> Duration {
        if self.times.len() < 2 {
            return Duration::ZERO;
        }
        let mean = self.mean();
        let variance: f64 = self.times.iter()
            .map(|t| {
                let diff = t.as_secs_f64() - mean.as_secs_f64();
                diff * diff
            })
            .sum::<f64>() / (self.times.len() - 1) as f64;
        Duration::from_secs_f64(variance.sqrt())
    }

    pub fn min(&self) -> Duration {
        self.times.iter().copied().min().unwrap_or(Duration::ZERO)
    }

    pub fn max(&self) -> Duration {
        self.times.iter().copied().max().unwrap_or(Duration::ZERO)
    }

    /// Print summary statistics
    pub fn print_summary(&self, label: &str) {
        println!("{} Performance:", label);
        println!("  Warmup runs: {}", self.warmup_runs);
        println!("  Measured runs: {}", self.measured_runs);
        println!("  Mean: {:?}", self.mean());
        println!("  Median: {:?}", self.median());
        println!("  Std Dev: {:?}", self.std_dev());
        println!("  Min: {:?}", self.min());
        println!("  Max: {:?}", self.max());
    }
}

/// Compare two implementations and report speedup
pub fn compare_implementations<F1, F2, R>(
    name1: &str,
    mut impl1: F1,
    name2: &str,
    mut impl2: F2,
    warmup: usize,
    measured: usize,
) -> ComparisonResult
where
    F1: FnMut() -> R,
    F2: FnMut() -> R,
{
    let mut perf1 = PerfMeasurement::new(warmup, measured);
    let mut perf2 = PerfMeasurement::new(warmup, measured);

    perf1.measure(&mut impl1);
    perf2.measure(&mut impl2);

    let speedup = perf1.mean().as_secs_f64() / perf2.mean().as_secs_f64();

    ComparisonResult {
        name1: name1.to_string(),
        mean1: perf1.mean(),
        name2: name2.to_string(),
        mean2: perf2.mean(),
        speedup,
    }
}

#[derive(Debug)]
pub struct ComparisonResult {
    pub name1: String,
    pub mean1: Duration,
    pub name2: String,
    pub mean2: Duration,
    pub speedup: f64,
}

impl ComparisonResult {
    pub fn print(&self) {
        println!("Performance Comparison:");
        println!("  {}: {:?}", self.name1, self.mean1);
        println!("  {}: {:?}", self.name2, self.mean2);
        println!("  Speedup: {:.2}x", self.speedup);
        if self.speedup > 1.0 {
            println!("  {} is {:.1}% faster", self.name2, (self.speedup - 1.0) * 100.0);
        } else {
            println!("  {} is {:.1}% faster", self.name1, (1.0 / self.speedup - 1.0) * 100.0);
        }
    }
}
